import{_ as i,o as a,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const b=JSON.parse('{"title":"性能调优与排障","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/13-Dubbo学习/06-性能调优与排障.md","filePath":"语言/java/13-Dubbo学习/06-性能调优与排障.md","lastUpdated":1777177198000}'),h={name:"语言/java/13-Dubbo学习/06-性能调优与排障.md"};function o(n,l,s,p,d,t){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="性能调优与排障" tabindex="-1">性能调优与排障 <a class="header-anchor" href="#性能调优与排障" aria-label="Permalink to “性能调优与排障”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>前面几章学完之后，你大概已经知道 Dubbo 是怎么工作的了。</p><p>但一到真实线上环境，问题通常不会按章节来：</p><ul><li>某个接口突然超时</li><li>某个服务错误率升高</li><li>某个 Consumer 越重试越糟</li><li>某台 Provider CPU 很高</li><li>明明网络通，调用还是慢</li></ul><p>这时候就进入了 Dubbo 最实战的一章：</p><ul><li><strong>性能调优</strong>：让调用更快、更稳、更省资源</li><li><strong>排障</strong>：当调用出问题时，快速找到真正瓶颈</li></ul><p>如果只用一句话概括：</p><blockquote><p><strong>Dubbo 排障不是只看一个报错，而是顺着整条 RPC 链路找哪一层出了问题。</strong></p></blockquote><hr><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>RPC 问题之所以难排，是因为它天然跨多个层次：</p><ul><li>Consumer 侧配置</li><li>注册发现</li><li>路由与负载均衡</li><li>网络传输</li><li>序列化/反序列化</li><li>Provider 业务执行</li><li>线程池</li><li>下游数据库/缓存/第三方依赖</li></ul><p>所以你看到一个“超时”，背后可能完全不是同一个原因：</p><ul><li>可能是网络慢</li><li>可能是下游 SQL 慢</li><li>可能是线程池满了</li><li>可能是重试把链路拖长了</li><li>可能是序列化对象太大</li></ul><p>这也是为什么 RPC 排障最忌讳：</p><ul><li>一看到超时，就先把超时值调大</li></ul><p>因为这常常只是把问题藏起来，而不是解决它。</p><hr><h2 id="_3-先建立排障总思路" tabindex="-1">3. 先建立排障总思路 <a class="header-anchor" href="#_3-先建立排障总思路" aria-label="Permalink to “3. 先建立排障总思路”">​</a></h2><p>你可以把一次 Dubbo 调用拆成 6 段：</p><ol><li>Consumer 发起调用</li><li>服务发现与选路</li><li>网络发送</li><li>Provider 接收并执行业务</li><li>Provider 返回结果</li><li>Consumer 收到并解析响应</li></ol><p>任何一段慢了，最终都可能表现成：</p><ul><li>超时</li><li>错误率高</li><li>RT 飙升</li></ul><p>所以排障时不要只问：</p><ul><li>“这个接口为什么超时？”</li></ul><p>而要进一步追问：</p><ul><li>“它到底慢在链路哪一段？”</li></ul><p>这个思路非常关键。</p><hr><h2 id="_4-最常见问题-1-超时" tabindex="-1">4. 最常见问题 1：超时 <a class="header-anchor" href="#_4-最常见问题-1-超时" aria-label="Permalink to “4. 最常见问题 1：超时”">​</a></h2><p>超时是 Dubbo 排障里最常见的表象之一。</p><p>但“超时”不是根因，只是结果。</p><h3 id="常见根因可能包括" tabindex="-1">常见根因可能包括 <a class="header-anchor" href="#常见根因可能包括" aria-label="Permalink to “常见根因可能包括”">​</a></h3><ul><li>Provider 业务逻辑慢</li><li>下游数据库查询慢</li><li>Provider 线程池积压</li><li>网络抖动</li><li>请求体/响应体过大</li><li>重试叠加导致总耗时过长</li><li>Consumer 超时配置过小</li></ul><h3 id="一句实战经验" tabindex="-1">一句实战经验 <a class="header-anchor" href="#一句实战经验" aria-label="Permalink to “一句实战经验”">​</a></h3><blockquote><p><strong>先找哪段慢，再决定调不调超时；不要先调超时，再假装问题解决。</strong></p></blockquote><hr><h2 id="_5-最常见问题-2-重试放大故障" tabindex="-1">5. 最常见问题 2：重试放大故障 <a class="header-anchor" href="#_5-最常见问题-2-重试放大故障" aria-label="Permalink to “5. 最常见问题 2：重试放大故障”">​</a></h2><p>很多系统在下游开始抖动时，会出现一种典型现象：</p><ul><li>本来只是少量请求变慢</li><li>Consumer 开启重试后</li><li>请求数被放大</li><li>下游更扛不住</li><li>最后整个链路一起雪崩</li></ul><p>这就是所谓的“重试放大问题”。</p><p>例如：</p><ul><li>原本 1000 QPS</li><li>每个失败请求再重试 2 次</li><li>实际打到下游的流量可能瞬间变成数倍</li></ul><p>所以重试不是默认收益，而是默认带风险。</p><p>特别是：</p><ul><li>下游本来就已经慢</li><li>线程池已经拥堵</li><li>数据库已经告警</li></ul><p>这时继续重试，往往是火上浇油。</p><hr><h2 id="_6-最常见问题-3-线程池和请求积压" tabindex="-1">6. 最常见问题 3：线程池和请求积压 <a class="header-anchor" href="#_6-最常见问题-3-线程池和请求积压" aria-label="Permalink to “6. 最常见问题 3：线程池和请求积压”">​</a></h2><p>Provider 侧如果线程池满了，会出现什么？</p><ul><li>新请求排队</li><li>响应时间变长</li><li>超时增多</li><li>CPU 未必很高，但整体调用已经很差</li></ul><p>这是很多人容易误判的点。</p><p>有些时候问题不是：</p><ul><li>机器不行</li></ul><p>而是：</p><ul><li>线程模型不合适</li><li>队列太长</li><li>任务执行时间太久</li></ul><p>所以看 Dubbo 性能时，不能只看：</p><ul><li>CPU</li><li>内存</li></ul><p>还要看：</p><ul><li>线程池活跃数</li><li>队列积压</li><li>请求等待时间</li></ul><hr><h2 id="_7-最常见问题-4-序列化和数据体积" tabindex="-1">7. 最常见问题 4：序列化和数据体积 <a class="header-anchor" href="#_7-最常见问题-4-序列化和数据体积" aria-label="Permalink to “7. 最常见问题 4：序列化和数据体积”">​</a></h2><p>很多人排查慢调用时，只盯业务代码，却忽略：</p><ul><li>请求对象是不是太大</li><li>返回对象是不是太复杂</li><li>序列化是不是很重</li></ul><p>例如：</p><ul><li>一个接口返回几十 KB、几百 KB 的对象</li><li>嵌套层级很多</li><li>字段冗余严重</li></ul><p>这会带来：</p><ul><li>序列化成本升高</li><li>网络传输时间增加</li><li>反序列化更慢</li></ul><p>所以优化 RPC 不一定只是优化 SQL，有时候也要先问：</p><ul><li>这个对象真的要传这么多字段吗？</li></ul><hr><h2 id="_8-最常见问题-5-网络没断-但就是慢" tabindex="-1">8. 最常见问题 5：网络没断，但就是慢 <a class="header-anchor" href="#_8-最常见问题-5-网络没断-但就是慢" aria-label="Permalink to “8. 最常见问题 5：网络没断，但就是慢”">​</a></h2><p>RPC 问题不一定是“网络不通”，更常见的是：</p><ul><li>网络可通</li><li>但延迟高</li><li>或有抖动</li><li>或跨机房路径不合理</li></ul><p>表现通常是：</p><ul><li>偶发超时</li><li>RT 波动很大</li><li>同一接口时好时坏</li></ul><p>所以排障时不能只问：</p><ul><li>ping 通不通</li></ul><p>还要看：</p><ul><li>延迟是否稳定</li><li>是否跨机房</li><li>是否有丢包/抖动</li></ul><hr><h2 id="_9-一套最实用的排障顺序" tabindex="-1">9. 一套最实用的排障顺序 <a class="header-anchor" href="#_9-一套最实用的排障顺序" aria-label="Permalink to “9. 一套最实用的排障顺序”">​</a></h2><p>以后你遇到 Dubbo 问题，我建议优先按这个顺序排：</p><h3 id="第一步-先确认现象" tabindex="-1">第一步：先确认现象 <a class="header-anchor" href="#第一步-先确认现象" aria-label="Permalink to “第一步：先确认现象”">​</a></h3><p>先弄清楚是：</p><ul><li>全量失败</li><li>部分失败</li><li>偶发失败</li><li>全部变慢</li><li>只有某个 Consumer 慢</li><li>只有某个 Provider 慢</li></ul><p>不要一上来就进入猜测。</p><h3 id="第二步-看关键指标" tabindex="-1">第二步：看关键指标 <a class="header-anchor" href="#第二步-看关键指标" aria-label="Permalink to “第二步：看关键指标”">​</a></h3><p>重点看：</p><ul><li>QPS</li><li>RT</li><li>超时数</li><li>错误率</li><li>重试次数</li><li>线程池活跃数</li><li>Provider 实例数</li></ul><h3 id="第三步-缩小范围" tabindex="-1">第三步：缩小范围 <a class="header-anchor" href="#第三步-缩小范围" aria-label="Permalink to “第三步：缩小范围”">​</a></h3><p>判断问题更可能在：</p><ul><li>Consumer 侧</li><li>网络侧</li><li>Provider 侧</li><li>下游依赖侧</li></ul><h3 id="第四步-结合日志和调用链" tabindex="-1">第四步：结合日志和调用链 <a class="header-anchor" href="#第四步-结合日志和调用链" aria-label="Permalink to “第四步：结合日志和调用链”">​</a></h3><p>例如看：</p><ul><li>哪个时间点开始变差</li><li>是否刚好发生扩容/发布/配置变更</li><li>哪个方法最慢</li><li>是否出现线程池拒绝、序列化异常、连接异常</li></ul><h3 id="第五步-最后再决定怎么调优" tabindex="-1">第五步：最后再决定怎么调优 <a class="header-anchor" href="#第五步-最后再决定怎么调优" aria-label="Permalink to “第五步：最后再决定怎么调优”">​</a></h3><p>是要：</p><ul><li>调超时</li><li>改重试</li><li>减小对象体积</li><li>扩容实例</li><li>优化 SQL</li><li>改线程池参数</li><li>做限流/降级</li></ul><p>这个顺序比“直接调参数”可靠得多。</p><hr><h2 id="_10-一个典型案例-接口超时-先看哪" tabindex="-1">10. 一个典型案例：接口超时，先看哪 <a class="header-anchor" href="#_10-一个典型案例-接口超时-先看哪" aria-label="Permalink to “10. 一个典型案例：接口超时，先看哪”">​</a></h2><p>假设现象是：</p><ul><li><code>queryUserProfile</code> 接口超时率突然升高</li></ul><p>建议先这样查：</p><ol><li>是所有 Consumer 都超时，还是某几个超时？</li><li>是所有 Provider 都慢，还是某一台慢？</li><li>最近有没有发布、扩容、配置变更？</li><li>Provider 线程池有没有积压？</li><li>Provider 下游数据库是不是变慢了？</li><li>Consumer 有没有配置重试，导致整体耗时被放大？</li></ol><p>这套问法能帮你很快从“一个表象”拆到“一个具体层次”。</p><hr><h2 id="_11-调优时最值得优先做的事" tabindex="-1">11. 调优时最值得优先做的事 <a class="header-anchor" href="#_11-调优时最值得优先做的事" aria-label="Permalink to “11. 调优时最值得优先做的事”">​</a></h2><p>很多人一说调优，就想直接改框架参数。</p><p>但实际最有性价比的优化，常常是这几类：</p><h3 id="_11-1-先减无效数据传输" tabindex="-1">11.1 先减无效数据传输 <a class="header-anchor" href="#_11-1-先减无效数据传输" aria-label="Permalink to “11.1 先减无效数据传输”">​</a></h3><ul><li>减少不必要字段</li><li>避免超大 DTO</li><li>避免层层嵌套返回</li></ul><h3 id="_11-2-先优化下游慢点" tabindex="-1">11.2 先优化下游慢点 <a class="header-anchor" href="#_11-2-先优化下游慢点" aria-label="Permalink to “11.2 先优化下游慢点”">​</a></h3><ul><li>SQL</li><li>Redis</li><li>外部 HTTP 接口</li><li>文件/磁盘 I/O</li></ul><p>因为很多 Dubbo 慢，本质不是 Dubbo 慢，而是：</p><ul><li>Dubbo 背后的业务执行慢</li></ul><h3 id="_11-3-合理设置超时和重试" tabindex="-1">11.3 合理设置超时和重试 <a class="header-anchor" href="#_11-3-合理设置超时和重试" aria-label="Permalink to “11.3 合理设置超时和重试”">​</a></h3><ul><li>不是越大越安全</li><li>不是越多越可靠</li></ul><h3 id="_11-4-观察线程池与并发模型" tabindex="-1">11.4 观察线程池与并发模型 <a class="header-anchor" href="#_11-4-观察线程池与并发模型" aria-label="Permalink to “11.4 观察线程池与并发模型”">​</a></h3><ul><li>是否积压</li><li>是否拒绝</li><li>是否存在长尾任务拖住线程</li></ul><h3 id="_11-5-监控必须先补齐" tabindex="-1">11.5 监控必须先补齐 <a class="header-anchor" href="#_11-5-监控必须先补齐" aria-label="Permalink to “11.5 监控必须先补齐”">​</a></h3><p>如果没有：</p><ul><li>RT</li><li>错误率</li><li>超时率</li><li>实例维度指标</li><li>调用链路追踪</li></ul><p>那所谓调优很容易变成拍脑袋。</p><hr><h2 id="_12-最容易踩的坑" tabindex="-1">12. 最容易踩的坑 <a class="header-anchor" href="#_12-最容易踩的坑" aria-label="Permalink to “12. 最容易踩的坑”">​</a></h2><h3 id="_12-1-请求慢就一味增大超时" tabindex="-1">12.1 请求慢就一味增大超时 <a class="header-anchor" href="#_12-1-请求慢就一味增大超时" aria-label="Permalink to “12.1 请求慢就一味增大超时”">​</a></h3><p>这几乎是最常见误区。</p><p>超时调大后，用户可能只是更晚失败，系统资源还会被占更久。</p><h3 id="_12-2-下游已经抖动-还继续加重试" tabindex="-1">12.2 下游已经抖动，还继续加重试 <a class="header-anchor" href="#_12-2-下游已经抖动-还继续加重试" aria-label="Permalink to “12.2 下游已经抖动，还继续加重试”">​</a></h3><p>这会把局部问题放大成系统问题。</p><h3 id="_12-3-不区分-偶发慢-和-持续慢" tabindex="-1">12.3 不区分“偶发慢”和“持续慢” <a class="header-anchor" href="#_12-3-不区分-偶发慢-和-持续慢" aria-label="Permalink to “12.3 不区分“偶发慢”和“持续慢””">​</a></h3><p>偶发抖动和稳定性故障，排查思路不完全一样。</p><h3 id="_12-4-只盯-dubbo-不看业务执行" tabindex="-1">12.4 只盯 Dubbo，不看业务执行 <a class="header-anchor" href="#_12-4-只盯-dubbo-不看业务执行" aria-label="Permalink to “12.4 只盯 Dubbo，不看业务执行”">​</a></h3><p>很多问题最终根因在：</p><ul><li>SQL</li><li>缓存击穿</li><li>线程阻塞</li><li>外部依赖过慢</li></ul><h3 id="_12-5-没有按实例维度看指标" tabindex="-1">12.5 没有按实例维度看指标 <a class="header-anchor" href="#_12-5-没有按实例维度看指标" aria-label="Permalink to “12.5 没有按实例维度看指标”">​</a></h3><p>平均值可能很好看，但其中一台机器已经明显异常。</p><hr><h2 id="_13-动手演练建议" tabindex="-1">13. 动手演练建议 <a class="header-anchor" href="#_13-动手演练建议" aria-label="Permalink to “13. 动手演练建议”">​</a></h2><h3 id="练习-1-模拟一个慢-provider" tabindex="-1">练习 1：模拟一个慢 Provider <a class="header-anchor" href="#练习-1-模拟一个慢-provider" aria-label="Permalink to “练习 1：模拟一个慢 Provider”">​</a></h3><p>在 Provider 某个方法里加：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Thread.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sleep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>观察：</p><ul><li>Consumer RT</li><li>超时数</li><li>重试行为</li></ul><h3 id="练习-2-模拟线程池积压" tabindex="-1">练习 2：模拟线程池积压 <a class="header-anchor" href="#练习-2-模拟线程池积压" aria-label="Permalink to “练习 2：模拟线程池积压”">​</a></h3><p>让 Provider 执行一个慢任务并并发压测，观察：</p><ul><li>线程池活跃数</li><li>请求排队</li><li>平均 RT 与 TP99</li></ul><h3 id="练习-3-模拟大对象传输" tabindex="-1">练习 3：模拟大对象传输 <a class="header-anchor" href="#练习-3-模拟大对象传输" aria-label="Permalink to “练习 3：模拟大对象传输”">​</a></h3><p>让接口返回一个明显偏大的 DTO，观察：</p><ul><li>RT 是否上升</li><li>序列化与反序列化是否变慢</li></ul><h3 id="练习-4-模拟错误调参" tabindex="-1">练习 4：模拟错误调参 <a class="header-anchor" href="#练习-4-模拟错误调参" aria-label="Permalink to “练习 4：模拟错误调参”">​</a></h3><p>故意把：</p><ul><li>超时调很大</li><li>重试次数调很多</li></ul><p>再观察系统在下游抖动时会不会更差。</p><hr><h2 id="_14-自测问题" tabindex="-1">14. 自测问题 <a class="header-anchor" href="#_14-自测问题" aria-label="Permalink to “14. 自测问题”">​</a></h2><ul><li>为什么 RPC 超时常常只是表象而不是根因？</li><li>为什么重试有时会让系统更糟？</li><li>排查 Dubbo 性能问题时，为什么线程池指标很重要？</li><li>为什么要关注请求/响应对象的体积？</li><li>遇到慢调用时，为什么不应该先习惯性调大超时？</li></ul><hr><h2 id="_15-这一章你至少要带走什么" tabindex="-1">15. 这一章你至少要带走什么 <a class="header-anchor" href="#_15-这一章你至少要带走什么" aria-label="Permalink to “15. 这一章你至少要带走什么”">​</a></h2><p>如果你看完只记住 5 件事，就记下面这 5 件：</p><ol><li><strong>Dubbo 排障一定要按链路拆，不要只盯报错表象</strong></li><li><strong>超时常常只是结果，真正问题可能在业务、网络、线程池或重试</strong></li><li><strong>重试和超时要一起看，否则很容易把问题放大</strong></li><li><strong>线程池、对象体积、下游依赖，都是 RPC 调优的高频关键点</strong></li><li><strong>没有监控、日志和调用链，调优大概率会变成猜测</strong></li></ol><p>把这套排障思路建立起来，后面你再遇到 Dubbo 调用慢、错误率高、超时飙升，就不会只会“改大超时再试试”了。</p>',165)])])}const c=i(h,[["render",o]]);export{b as __pageData,c as default};
